-- ARCs (bots) do arc-data.js -> tabela public.arcs
-- Idempotente: ON CONFLICT DO UPDATE (upsert por id).
-- As imagens ficam em /assets/bots/<id>.png (servidas como arquivos estaticos)

on conflict (id) do update set
  name        = excluded.name,
  name_en     = excluded.name_en,
  description = excluded.description,
  description_en = excluded.description_en,
  type        = excluded.type,
  threat      = excluded.threat,
  weakness    = excluded.weakness,
  weakness_en = excluded.weakness_en,
  destroy_xp  = excluded.destroy_xp,
  loot_xp     = excluded.loot_xp,
  drops       = excluded.drops,
  image_url   = excluded.image_url,
  active      = excluded.active;
